# ruff: noqa: F401,F403,F405,F811,F821
SOURCE = '"""Deterministic autonomous lane: research -> gate evaluation -> paper candidate patch."""\n# pyright: reportMissingImports=false, reportMissingTypeStubs=false, reportUnknownVariableType=false, reportUnknownMemberType=false, reportUnknownArgumentType=false, reportUnknownParameterType=false, reportUnknownLambdaType=false, reportUnusedImport=false, reportUnusedClass=false, reportUnusedFunction=false, reportUnusedVariable=false, reportUndefinedVariable=false, reportUnsupportedDunderAll=false, reportAttributeAccessIssue=false, reportUntypedBaseClass=false, reportGeneralTypeIssues=false, reportInvalidTypeForm=false, reportReturnType=false, reportOptionalMemberAccess=false, reportArgumentType=false, reportCallIssue=false, reportPrivateUsage=false, reportUnnecessaryComparison=false, reportUnnecessaryCast=false\n\nfrom __future__ import annotations\n\nimport hashlib\nimport json\nimport math\nimport re\nfrom dataclasses import dataclass, field\nfrom datetime import datetime, timezone\nfrom decimal import Decimal\nfrom pathlib import Path\nfrom typing import Any, Callable, Mapping, Sequence, cast\n\nfrom sqlalchemy import delete, select\nfrom sqlalchemy.orm import Session\n\nimport pandas as pd\nimport yaml\n\nfrom ...config import settings\nfrom ...db import SessionLocal\nfrom ...models import (\n    ResearchAttempt,\n    ResearchCandidate,\n    ResearchCostCalibration,\n    ResearchFoldMetrics,\n    ResearchPromotion,\n    ResearchRun,\n    ResearchSequentialTrial,\n    ResearchStressMetrics,\n    ResearchValidationTest,\n    StrategyCapitalAllocation,\n    StrategyHypothesis,\n    StrategyHypothesisMetricWindow,\n    StrategyHypothesisVersion,\n    StrategyPromotionDecision,\n    Strategy,\n    VNextDatasetSnapshot,\n    VNextExperimentRun,\n    VNextExperimentSpec,\n    VNextFeatureViewSpec,\n    VNextModelArtifact,\n    VNextPromotionDecision,\n    VNextShadowLiveDeviation,\n    VNextSimulationCalibration,\n)\nfrom ..alpha.lane import AlphaLaneResult, run_alpha_discovery_lane\nfrom ..completion import build_completion_trace, persist_completion_trace\nfrom ..evaluation import (\n    FoldResult,\n    ProfitabilityEvidenceThresholdsV4,\n    WalkForwardDecision,\n    WalkForwardFold,\n    WalkForwardResults,\n    build_profitability_evidence_v4,\n    build_shadow_live_deviation_report_v1,\n    build_simulation_calibration_report_v1,\n    execute_profitability_benchmark_v4,\n    validate_profitability_evidence_v4,\n    write_walk_forward_results,\n)\nfrom ..evidence_contracts import (\n    ArtifactProvenance,\n    EvidenceMaturity,\n    contract_from_artifact_payload,\n    evidence_contract_payload,\n)\nfrom ..features import (\n    FeatureNormalizationError,\n    extract_price,\n    extract_rsi,\n    extract_signal_features,\n    normalize_feature_vector_v3,\n)\nfrom ..forecasting import build_default_forecast_router\nfrom ..hypotheses import (\n    hypothesis_registry_requires_dependency_capability,\n    load_hypothesis_registry,\n    resolve_hypothesis_dependency_quorum,\n)\nfrom ..llm.evaluation import build_llm_evaluation_metrics\nfrom ..models import SignalEnvelope\nfrom ..parity import (\n    build_advisor_fallback_slo_report,\n    build_benchmark_parity_report,\n    build_deeplob_bdlob_report,\n    build_foundation_router_parity_report,\n    write_advisor_fallback_slo_report,\n    write_benchmark_parity_report,\n    write_deeplob_bdlob_report,\n    write_foundation_router_parity_report,\n)\nfrom ..regime_hmm import HMM_UNKNOWN_REGIME_ID, resolve_hmm_context\nfrom ..reporting import (\n    EvaluationReport,\n    EvaluationReportConfig,\n    PromotionRecommendation,\n    build_promotion_recommendation,\n    generate_evaluation_report,\n    write_evaluation_report,\n)\nfrom ..strategy_specs import (\n    build_compiled_strategy_artifacts,\n    build_experiment_spec_from_strategy,\n    compile_strategy_spec_v2,\n    load_strategy_spec_v2_payload,\n    strategy_type_supports_spec_v2,\n)\nfrom ..tca import build_tca_gate_inputs\nfrom .gates import (\n    GateEvaluationReport,\n    GateInputs,\n    GatePolicyMatrix,\n    PromotionTarget,\n    evaluate_gate_matrix,\n)\nfrom .janus_q import (\n    build_janus_event_car_artifact_v1,\n    build_janus_hgrm_reward_artifact_v1,\n    build_janus_q_evidence_summary_v1,\n)\nfrom .policy_checks import (\n    RollbackReadinessResult,\n    evaluate_promotion_prerequisites,\n    evaluate_rollback_readiness,\n)\nfrom .runtime import (\n    StrategyRuntime,\n    StrategyRuntimeConfig,\n    compile_runtime_config,\n    default_runtime_registry,\n)\nfrom .phase_manifest_contract import (\n    AUTONOMY_PHASE_ORDER,\n    coerce_phase_status,\n    normalize_phase_transitions,\n)\n\n\n_AUTONOMY_PHASE_ORDER: tuple[str, ...] = AUTONOMY_PHASE_ORDER\n\n\n_ACTUATION_INTENT_SCHEMA_VERSION = "torghut.autonomy.actuation-intent.v1"\n_ACTUATION_CONFIRMATION_PHRASE = "ACTUATE_TORGHUT"\n_ACTUATION_INTENT_PATH = "gates/actuation-intent.json"\n_AUTONOMY_LANE_SCHEMA_VERSION = "torghut-autonomy-stage-manifest-v1"\n_PROFITABILITY_STAGE_MANIFEST_SCHEMA_VERSION = (\n    "profitability-stage-manifest-v1"\n)\n_PROFITABILITY_STAGE_MANIFEST_PATH = "profitability/profitability-stage-manifest-v1.json"\n_STAGE_CANDIDATE_GENERATION = "candidate-generation"\n_STAGE_EVALUATION = "evaluation"\n_STAGE_RECOMMENDATION = "promotion-recommendation"\n_STRESS_METRICS_ARTIFACT_PATH = "stress-metrics-v1.json"\n_CONTAMINATION_REGISTRY_ARTIFACT_PATH = "contamination-leakage-report-v1.json"\n_HMM_STATE_POSTERIOR_ARTIFACT_PATH = "gates/hmm-state-posterior-v1.json"\n_EXPERT_ROUTER_REGISTRY_ARTIFACT_PATH = "gates/expert-router-registry-v1.json"\n_FOLD_METRICS_ARTIFACT_PATH = "fold-metrics-v1.json"\n_STRESS_METRICS_CASES = ("spread", "volatility", "liquidity", "halt")\n_BENCHMARK_PARITY_REPORT_PATH = "gates/benchmark-parity-report-v1.json"\n_FOUNDATION_ROUTER_PARITY_REPORT_PATH = "router/foundation-router-parity-report-v1.json"\n_DEEPLOB_BDLOB_REPORT_PATH = "microstructure/deeplob-bdlob-report-v1.json"\n_ADVISOR_FALLBACK_SLO_REPORT_PATH = "execution/advisor-fallback-slo-report-v1.json"\n_STAGE_PROFITABILITY = "profitability_stage_manifest"\n_V6_08_GOVERNING_DESIGN_DOC = (\n    "docs/torghut/design-system/v6/08-profitability-research-validation-execution-governance-system.md"\n)\n\n\n@dataclass(frozen=True)\nclass _StageManifestRecord:\n    stage: str\n    stage_index: int\n    stage_trace_id: str\n    lineage_hash: str\n    artifact_hashes: dict[str, str]\n    stage_payload_hash: str\n    created_at: str\n    created_by: str = "run_autonomous_lane"\n    parent_lineage_hash: str | None = None\n    parent_stage: str | None = None\n    inputs: dict[str, str] = field(default_factory=dict)\n\n\ndef _coerce_evidence_bool(value: object) -> bool | None:\n    if isinstance(value, bool):\n        return value\n    if isinstance(value, int | float):\n        if not math.isfinite(value):\n            return None\n        return value != 0\n    if value is None:\n        return None\n    normalized = str(value).strip().lower()\n    if normalized in {"true", "1", "yes", "on"}:\n        return True\n    if normalized in {"false", "0", "no", "off", ""}:\n        return False\n    return None\n\n\ndef _normalize_strategy_artifacts(value: object) -> object | None:\n    if not isinstance(value, dict):\n        return value\n\n    kind = str(value.get("kind", "")).strip().lower()\n    if kind == "configmap":\n        data = value.get("data")\n        if not isinstance(data, dict):\n            return None\n        strategies_yaml = data.get("strategies.yaml")\n        if not isinstance(strategies_yaml, str):\n            return None\n        try:\n            nested_payload = yaml.safe_load(strategies_yaml)\n        except Exception:\n            return None\n        return _normalize_strategy_artifacts(nested_payload)\n\n    return value\n\n\ndef _is_runbook_valid(strategy_configmap_path: Path | None) -> bool:\n    resolved_path = strategy_configmap_path or _default_strategy_configmap_path()\n    if not resolved_path.exists() or not resolved_path.is_file():\n        return False\n\n    try:\n        raw_payload = yaml.safe_load(resolved_path.read_text(encoding="utf-8"))\n    except Exception:\n        return False\n\n    normalized_payload = _normalize_strategy_artifacts(raw_payload)\n\n    if normalized_payload is None:\n        return False\n\n    if isinstance(normalized_payload, dict):\n        strategies = normalized_payload.get("strategies")\n    elif isinstance(normalized_payload, list):\n        strategies = normalized_payload\n    else:\n        return False\n\n    if not isinstance(strategies, list):\n        return False\n\n    return bool(strategies) and all(isinstance(item, dict) for item in strategies)\n\n\ndef _build_candidate_state_payload(\n    *,\n    candidate_id: str,\n    run_id: str,\n    promotion_target: PromotionTarget,\n    approval_token: str | None,\n    runtime_strategies: list[StrategyRuntimeConfig],\n    now: datetime,\n    code_version: str,\n    runbook_validated: bool,\n    dependency_quorum_payload: dict[str, Any],\n    alpha_readiness_payload: dict[str, Any],\n) -> dict[str, Any]:\n    return {\n        "candidateId": candidate_id,\n        "runId": run_id,\n        "activeStage": "gate-evaluation",\n        "paused": False,\n        "datasetSnapshotRef": "signals_window",\n        "noSignalReason": None,\n        "runbookValidated": runbook_validated,\n        "dependencyQuorum": dependency_quorum_payload,\n        "alphaReadiness": alpha_readiness_payload,\n        "rollbackReadiness": {\n            "killSwitchDryRunPassed": bool(runtime_strategies),\n            "gitopsRevertDryRunPassed": (\n                promotion_target != "live" or bool(approval_token)\n            ),\n            "strategyDisableDryRunPassed": bool(runtime_strategies),\n            "dryRunCompletedAt": now.isoformat(),\n            "humanApproved": promotion_target != "live" or bool(approval_token),\n            "rollbackTarget": f"{code_version or \'unknown\'}",\n        },\n    }\n\n\ndef _build_candidate_alpha_readiness_payload(\n    *,\n    runtime_strategies: Sequence[StrategyRuntimeConfig],\n) -> tuple[dict[str, Any], dict[str, Any]]:\n    registry = load_hypothesis_registry()\n    dependency_quorum = resolve_hypothesis_dependency_quorum(registry)\n    strategy_families = sorted(\n        {\n            str(strategy.strategy_type).strip()\n            for strategy in runtime_strategies\n            if str(strategy.strategy_type).strip()\n        }\n    )\n    matched_hypotheses = [\n        manifest\n        for manifest in registry.items\n        if manifest.strategy_family in strategy_families\n    ]\n    matched_strategy_families = {\n        manifest.strategy_family for manifest in matched_hypotheses\n    }\n    missing_strategy_families = sorted(\n        family\n        for family in strategy_families\n        if family not in matched_strategy_families\n    )\n    reasons: list[str] = []\n    if not registry.loaded:\n        reasons.append("hypothesis_registry_unavailable")\n    if registry.errors:\n        reasons.append("hypothesis_registry_errors_present")\n    if missing_strategy_families:\n        reasons.append("strategy_family_hypothesis_unmapped")\n    if dependency_quorum.decision != "allow":\n        reasons.append(f"jangar_dependency_quorum_{dependency_quorum.decision}")\n    return (\n        {\n            "mode": "candidate_alignment_v1",\n            "registry_loaded": registry.loaded,\n            "registry_path": registry.path,\n            "registry_errors": list(registry.errors),\n            "strategy_families": strategy_families,\n            "matched_hypothesis_ids": sorted(\n                {manifest.hypothesis_id for manifest in matched_hypotheses}\n            ),\n            "missing_strategy_families": missing_strategy_families,\n            "promotion_eligible": (\n                registry.loaded\n                and not registry.errors\n                and not missing_strategy_families\n                and dependency_quorum.decision == "allow"\n            ),\n            "reasons": reasons,\n            "dependency_quorum": dependency_quorum.as_payload(),\n        },\n        dependency_quorum.as_payload(),\n    )\n\n\n@dataclass(frozen=True)\nclass AutonomousLaneResult:\n    run_id: str\n    candidate_id: str\n    output_dir: Path\n    gate_report_path: Path\n    actuation_intent_path: Path | None\n    paper_patch_path: Path | None\n    phase_manifest_path: Path\n    benchmark_parity_path: Path\n    foundation_router_parity_path: Path\n    gate_report_trace_id: str\n    recommendation_trace_id: str\n    recommendation_artifact_path: Path\n    candidate_spec_path: Path\n    candidate_generation_manifest_path: Path\n    evaluation_manifest_path: Path\n    recommendation_manifest_path: Path\n    profitability_manifest_path: Path\n    stage_trace_ids: dict[str, str] = field(default_factory=dict)\n    stage_lineage_root: str | None = None\n\n\n@dataclass(frozen=True)\nclass _StrategyFactoryBridge:\n    result: AlphaLaneResult\n    candidate_spec_payload: dict[str, Any]\n    evaluation_payload: dict[str, Any]\n    recommendation_payload: dict[str, Any]\n    attempt_payload: dict[str, Any]\n    validation_payloads: dict[str, dict[str, Any]]\n    sequential_trial_payload: dict[str, Any]\n    cost_calibration_payload: dict[str, Any]\n\n\ndef _load_price_frame(path: Path) -> pd.DataFrame:\n    return pd.read_csv(path, index_col=0, parse_dates=True)\n\n\ndef _build_strategy_factory_bridge(\n    *,\n    output_dir: Path,\n    notes_artifact_root: str | None,\n    train_prices_path: Path | None,\n    test_prices_path: Path | None,\n    alpha_gate_policy_path: Path | None,\n    repository: str | None,\n    base: str | None,\n    head: str | None,\n    priority_id: str | None,\n    promotion_target: str,\n    now: datetime,\n) -> _StrategyFactoryBridge | None:\n    if train_prices_path is None or test_prices_path is None:\n        return None\n\n    bridge_result = run_alpha_discovery_lane(\n        artifact_path=output_dir / \'strategy-factory\',\n        train_prices=_load_price_frame(train_prices_path),\n        test_prices=_load_price_frame(test_prices_path),\n        repository=repository,\n        base=base,\n        head=head,\n        priority_id=priority_id,\n        notes_artifact_path=notes_artifact_root,\n        gate_policy_path=alpha_gate_policy_path,\n        promotion_target=promotion_target,\n        evaluated_at=now,\n        persist_results=False,\n    )\n    validation_payloads: dict[str, dict[str, Any]] = {}\n    for test_name, artifact_path in bridge_result.validation_artifact_paths.items():\n        validation_payload = _load_json_if_exists(artifact_path)\n        if validation_payload is None:\n            continue\n        validation_payloads[test_name] = validation_payload\n    return _StrategyFactoryBridge(\n        result=bridge_result,\n        candidate_spec_payload=_load_json_if_exists(bridge_result.candidate_spec_path)\n        or {},\n        evaluation_payload=_load_json_if_exists(bridge_result.evaluation_report_path)\n        or {},\n        recommendation_payload=_load_json_if_exists(\n            bridge_result.recommendation_artifact_path\n        )\n        or {},\n        attempt_payload=_load_json_if_exists(bridge_result.attempt_ledger_path) or {},\n        validation_payloads=validation_payloads,\n        sequential_trial_payload=_load_json_if_exists(\n            bridge_result.sequential_trial_path\n        )\n        or {},\n        cost_calibration_payload=_load_json_if_exists(\n            bridge_result.cost_calibration_path\n        )\n        or {},\n    )\n\n\ndef _strategy_factory_gate_summary(\n    bridge: _StrategyFactoryBridge,\n    *,\n    promotion_target: str,\n) -> tuple[bool, list[str], dict[str, Any]]:\n    reasons: list[str] = []\n    recommendation = (\n        cast(dict[str, Any], bridge.recommendation_payload.get(\'recommendation\'))\n        if isinstance(bridge.recommendation_payload.get(\'recommendation\'), dict)\n        else {}\n    )\n    strategy_payload = (\n        cast(dict[str, Any], bridge.candidate_spec_payload.get(\'strategy_factory\'))\n        if isinstance(bridge.candidate_spec_payload.get(\'strategy_factory\'), dict)\n        else {}\n    )\n    economic_card = (\n        cast(dict[str, Any], strategy_payload.get(\'economic_validity_card\'))\n        if isinstance(strategy_payload.get(\'economic_validity_card\'), dict)\n        else {}\n    )\n    comparator = (\n        cast(dict[str, Any], strategy_payload.get(\'null_comparator_summary\'))\n        if isinstance(strategy_payload.get(\'null_comparator_summary\'), dict)\n        else {}\n    )\n    sequential = bridge.sequential_trial_payload\n    calibration = bridge.cost_calibration_payload\n\n    if not bool(recommendation.get(\'eligible\')):\n        reasons.append(\'strategy_factory_recommendation_not_eligible\')\n    if str(economic_card.get(\'status\') or \'\').strip().lower() != \'pass\':\n        reasons.append(\'strategy_factory_economic_validity_failed\')\n    if not bool(comparator.get(\'baseline_outperformed\')):\n        reasons.append(\'strategy_factory_baseline_not_outperformed\')\n\n    sequential_status = str(sequential.get(\'status\') or \'\').strip().lower()\n    calibration_status = str(calibration.get(\'status\') or \'\').strip().lower()\n    if promotion_target in {\'paper\', \'live\'} and sequential_status not in {\n        \'paper_ready\',\n        \'paper_only\',\n    }:\n        reasons.append(\'strategy_factory_sequential_not_ready\')\n    if promotion_target == \'live\':\n        if sequential_status != \'paper_ready\':\n            reasons.append(\'strategy_factory_live_requires_paper_ready\')\n        if calibration_status != \'calibrated\':\n            reasons.append(\'strategy_factory_live_requires_calibrated_costs\')\n\n    summary = {\n        \'allowed\': len(reasons) == 0,\n        \'reasons\': reasons,\n        \'candidate_spec_artifact\': str(bridge.result.candidate_spec_path),\n        \'evaluation_artifact\': str(bridge.result.evaluation_report_path),\n        \'recommendation_artifact\': str(bridge.result.recommendation_artifact_path),\n        \'attempt_ledger_artifact\': str(bridge.result.attempt_ledger_path),\n        \'sequential_trial_artifact\': str(bridge.result.sequential_trial_path),\n        \'cost_calibration_artifact\': str(bridge.result.cost_calibration_path),\n        \'sequential_status\': sequential_status or None,\n        \'cost_calibration_status\': calibration_status or None,\n        \'baseline_outperformed\': comparator.get(\'baseline_outperformed\'),\n        \'posterior_edge_summary\': strategy_payload.get(\'posterior_edge_summary\'),\n    }\n    return len(reasons) == 0, reasons, summary\n\n\ndef _strategy_factory_artifact_refs(\n    bridge: _StrategyFactoryBridge | None,\n) -> list[str]:\n    if bridge is None:\n        return []\n    refs = [\n        bridge.result.candidate_spec_path,\n        bridge.result.evaluation_report_path,\n        bridge.result.recommendation_artifact_path,\n        bridge.result.attempt_ledger_path,\n        bridge.result.sequential_trial_path,\n        bridge.result.cost_calibration_path,\n        bridge.result.candidate_generation_manifest_path,\n        bridge.result.evaluation_manifest_path,\n        bridge.result.recommendation_manifest_path,\n        *bridge.result.validation_artifact_paths.values(),\n    ]\n    return [str(path) for path in refs]\n\n\ndef upsert_autonomy_no_signal_run(\n    *,\n    session_factory: Callable[[], Session],\n    query_start: datetime,\n    query_end: datetime,\n    strategy_config_path: Path,\n    gate_policy_path: Path,\n    no_signal_reason: str | None,\n    now: datetime,\n    code_version: str = "live",\n) -> str:\n    """Persist a zero-signal window as a skipped research run."""\n\n    strategy: StrategyRuntimeConfig | None = None\n    try:\n        runtime_strategies = load_runtime_strategy_config(strategy_config_path)\n        strategy = runtime_strategies[0] if runtime_strategies else None\n    except Exception:\n        strategy = None\n\n    strategy_id = strategy.strategy_id if strategy else None\n    strategy_type = strategy.strategy_type if strategy else None\n    strategy_version = strategy.version if strategy else None\n\n    reason_label = (no_signal_reason or "no_signal").strip()\n    query_start_utc = _ensure_utc(query_start)\n    query_end_utc = _ensure_utc(query_end)\n\n    run_signature = {\n        "query_start": query_start_utc.isoformat() if query_start_utc else None,\n        "query_end": query_end_utc.isoformat() if query_end_utc else None,\n        "strategy_config_path": str(strategy_config_path),\n        "reason": reason_label,\n    }\n    run_signature_bytes = json.dumps(run_signature, sort_keys=True).encode("utf-8")\n    run_id = hashlib.sha256(run_signature_bytes).hexdigest()[:24]\n\n    feature_spec_hash = _compute_no_signal_feature_spec_hash(\n        strategy_config_path=strategy_config_path,\n        gate_policy_path=gate_policy_path,\n        reason=reason_label,\n        query_start=query_start_utc,\n        query_end=query_end_utc,\n    )\n    dataset_version = _compute_no_signal_dataset_version_hash(\n        query_start=query_start_utc,\n        query_end=query_end_utc,\n        no_signal_reason=reason_label,\n    )\n\n    with session_factory() as session:\n        existing_run = session.execute(\n            select(ResearchRun).where(ResearchRun.run_id == run_id)\n        ).scalar_one_or_none()\n\n        if existing_run is None:\n            run = ResearchRun(\n                run_id=run_id,\n                status="skipped",\n                strategy_id=strategy_id,\n                strategy_name=strategy_id,\n                strategy_type=strategy_type,\n                strategy_version=strategy_version,\n                code_commit=code_version,\n                feature_version=settings.trading_feature_normalization_version,\n                feature_schema_version=settings.trading_feature_schema_version,\n                feature_spec_hash=feature_spec_hash,\n                signal_source="autonomy-signals",\n                dataset_version=dataset_version,\n                dataset_from=query_start_utc,\n                dataset_to=query_end_utc,\n                dataset_snapshot_ref="no_signal_window",\n                runner_version="run_autonomous_lane_no_signals",\n                runner_binary_hash=hashlib.sha256(run_id.encode("utf-8")).hexdigest(),\n                updated_at=now,\n            )\n            session.add(run)\n        else:\n            existing_run.status = "skipped"\n            existing_run.strategy_id = strategy_id\n            existing_run.strategy_name = strategy_id\n            existing_run.strategy_type = strategy_type\n            existing_run.strategy_version = strategy_version\n            existing_run.code_commit = code_version\n            existing_run.feature_version = (\n                settings.trading_feature_normalization_version\n            )\n            existing_run.feature_spec_hash = feature_spec_hash\n            existing_run.feature_schema_version = (\n                settings.trading_feature_schema_version\n            )\n            existing_run.signal_source = "autonomy-signals"\n            existing_run.dataset_version = dataset_version\n            existing_run.dataset_from = query_start_utc\n            existing_run.dataset_to = query_end_utc\n            existing_run.dataset_snapshot_ref = "no_signal_window"\n            existing_run.runner_version = "run_autonomous_lane_no_signals"\n            existing_run.runner_binary_hash = hashlib.sha256(\n                run_id.encode("utf-8")\n            ).hexdigest()\n            existing_run.updated_at = now\n            session.add(existing_run)\n        session.commit()\n        return run_id\n\n\ndef _ensure_utc(value: datetime) -> datetime:\n    return value if value.tzinfo is not None else value.replace(tzinfo=timezone.utc)\n\n\ndef _safe_int(value: Any) -> int:\n    try:\n        return int(value)\n    except (TypeError, ValueError):\n        return 0\n\n\ndef _as_object_dict(value: object) -> dict[str, object]:\n    if not isinstance(value, dict):\n        return {}\n    return {str(key): item for key, item in value.items()}\n\ndef _stable_hash(payload: object) -> str:\n    payload_json = json.dumps(payload, sort_keys=True, separators=(",", ":"))\n    return hashlib.sha256(payload_json.encode("utf-8")).hexdigest()\n\n\ndef _artifact_hashes(artifacts: Mapping[str, Path | None]) -> dict[str, str]:\n    digests: dict[str, str] = {}\n    for key, artifact_path in artifacts.items():\n        if artifact_path is not None and artifact_path.exists():\n            digests[key] = _sha256_path(artifact_path)\n    return digests\n\n\ndef _readable_notes_iteration_number(notes_dir: Path) -> int:\n    pattern = re.compile(r"^iteration-(\\d+)\\.md$")\n    highest = 0\n    for item in notes_dir.glob("iteration-*.md"):\n        match = pattern.match(item.name)\n        if not match:\n            continue\n        try:\n            candidate = int(match.group(1))\n        except (TypeError, ValueError):\n            continue\n        if candidate > highest:\n            highest = candidate\n    return highest + 1\n\n\ndef _write_stage_manifest(\n    *,\n    stage: str,\n    stage_index: int,\n    stage_output_dir: Path,\n    run_id: str,\n    candidate_id: str,\n    lineage_parent_hash: str | None,\n    lineage_parent_stage: str | None,\n    inputs: dict[str, str],\n    input_artifacts: Mapping[str, Path | None],\n    output_artifacts: Mapping[str, Path | None],\n    created_at: datetime,\n) -> _StageManifestRecord:\n    stage_manifest = {\n        "schema_version": _AUTONOMY_LANE_SCHEMA_VERSION,\n        "stage": stage,\n        "stage_index": stage_index,\n        "run_id": run_id,\n        "candidate_id": candidate_id,\n        "created_at": created_at.isoformat(),\n        "inputs": dict(inputs),\n        "input_artifacts": {\n            key: {\n                "path": str(path),\n                "sha256": _sha256_path(path),\n            }\n            for key, path in input_artifacts.items()\n            if path is not None\n        },\n        "output_artifacts": {\n            key: {\n                "path": str(path),\n                "sha256": _sha256_path(path),\n            }\n            for key, path in output_artifacts.items()\n            if path is not None\n        },\n        "parent_lineage_hash": lineage_parent_hash,\n        "parent_stage": lineage_parent_stage,\n    }\n    stage_payload_hash = _stable_hash(stage_manifest)\n    stage_trace_id = stage_payload_hash[:24]\n    artifact_hashes = _artifact_hashes(output_artifacts)\n    record = _StageManifestRecord(\n        stage=stage,\n        stage_index=stage_index,\n        stage_trace_id=stage_trace_id,\n        lineage_hash=stage_payload_hash,\n        artifact_hashes=artifact_hashes,\n        stage_payload_hash=stage_payload_hash,\n        created_at=created_at.isoformat(),\n        parent_lineage_hash=lineage_parent_hash,\n        parent_stage=lineage_parent_stage,\n        inputs=dict(inputs),\n    )\n    stage_manifest["stage_trace_id"] = stage_trace_id\n    stage_manifest["lineage_hash"] = stage_payload_hash\n    stage_manifest["artifact_hashes"] = artifact_hashes\n    manifest_path = stage_output_dir / f"{stage}-manifest.json"\n    stage_manifest["artifact_count"] = len(artifact_hashes)\n    manifest_path.write_text(json.dumps(stage_manifest, indent=2), encoding="utf-8")\n    return record\n\n\ndef _build_stage_lineage_payload(\n    stage_records: Sequence[_StageManifestRecord],\n    manifest_paths: Mapping[str, Path],\n) -> dict[str, Any]:\n    stages_payload: dict[str, Any] = {}\n    for record in stage_records:\n        manifest_path = manifest_paths.get(record.stage)\n        stages_payload[record.stage] = {\n            "index": record.stage_index,\n            "stage_trace_id": record.stage_trace_id,\n            "lineage_hash": record.lineage_hash,\n            "parent_stage": record.parent_stage,\n            "parent_lineage_hash": record.parent_lineage_hash,\n            "stage_payload_hash": record.stage_payload_hash,\n            "created_at": record.created_at,\n            "created_by": record.created_by,\n            "inputs": record.inputs,\n            "artifact_hashes": record.artifact_hashes,\n            "manifest_path": str(manifest_path) if manifest_path else None,\n        }\n    return {\n        "schema_version": _AUTONOMY_LANE_SCHEMA_VERSION,\n        "root_lineage_hash": stage_records[0].lineage_hash if stage_records else None,\n        "stages": stages_payload,\n    }\n\n\ndef _manifest_relative_path(artifact_root: Path, artifact_path: Path) -> str:\n    try:\n        return str(artifact_path.relative_to(artifact_root))\n    except ValueError:\n        return str(artifact_path)\n\n\ndef _artifact_authority_for_check(\n    *,\n    stage_name: str,\n    check_name: str,\n) -> dict[str, Any] | None:\n    if check_name in {\n        "benchmark_parity_present",\n        "foundation_router_parity_present",\n        "janus_event_car_present",\n        "janus_hgrm_reward_present",\n        "expert_router_registry_present",\n        "hmm_state_posterior_present",\n    }:\n        return evidence_contract_payload(\n            provenance=ArtifactProvenance.SYNTHETIC_GENERATED,\n            maturity=EvidenceMaturity.STUB,\n            authoritative=False,\n            placeholder=True,\n            notes="Deterministic scaffold artifact; never promotion-authoritative.",\n        )\n    if check_name in {\n        "evaluation_report_present",\n        "walkforward_results_present",\n        "baseline_evaluation_report_present",\n        "profitability_benchmark_present",\n        "profitability_evidence_present",\n        "profitability_validation_present",\n        "contamination_registry_present",\n        "advisor_fallback_slo_present",\n        "recalibration_report_present",\n        "gate_report_present",\n    }:\n        return evidence_contract_payload(\n            provenance=ArtifactProvenance.HISTORICAL_MARKET_REPLAY,\n            maturity=EvidenceMaturity.UNCALIBRATED,\n            calibration_summary={\n                "status": "pending_calibration",\n                "stage": stage_name,\n                "check": check_name,\n            },\n        )\n    return None\n\n\ndef _artifact_authority_for_evidence(name: str) -> dict[str, Any]:\n    evidence_name = name.strip().lower()\n    if evidence_name in {\n        "benchmark_parity",\n        "foundation_router_parity",\n        "janus_event_car",\n        "janus_hgrm_reward",\n        "janus_q",\n        "hmm_state_posterior",\n        "expert_router_registry",\n        "deeplob_bdlob_contract",\n    }:\n        return evidence_contract_payload(\n            provenance=ArtifactProvenance.SYNTHETIC_GENERATED,\n            maturity=EvidenceMaturity.STUB,\n            authoritative=False,\n            placeholder=True,\n            notes="Synthetic or deterministic scaffold evidence; blocked for promotion.",\n        )\n    return evidence_contract_payload(\n        provenance=ArtifactProvenance.HISTORICAL_MARKET_REPLAY,\n        maturity=EvidenceMaturity.UNCALIBRATED,\n        calibration_summary={\n            "status": "pending_calibration",\n            "evidence_name": evidence_name,\n        },\n    )\n\n\ndef _empirical_artifact_authority(\n    *,\n    evidence_name: str,\n    provenance: ArtifactProvenance = ArtifactProvenance.HISTORICAL_MARKET_REPLAY,\n) -> dict[str, Any]:\n    return evidence_contract_payload(\n        provenance=provenance,\n        maturity=EvidenceMaturity.EMPIRICALLY_VALIDATED,\n        authoritative=True,\n        placeholder=False,\n        calibration_summary={\n            "status": "external_empirical_source",\n            "evidence_name": evidence_name,\n        },\n        notes="Artifact loaded from configured empirical source.",\n    )\n\n\ndef _resolve_optional_service_path(raw_value: str | None) -> Path | None:\n    normalized = (raw_value or \'\').strip()\n    if not normalized:\n        return None\n    path = Path(normalized).expanduser()\n    if path.is_absolute():\n        return path\n    service_root = Path(__file__).resolve().parents[3]\n    return service_root / path\n\n\ndef _load_configured_empirical_payload(\n    *,\n    path_value: str | None,\n    expected_schema_version: str | None,\n    evidence_name: str,\n    provenance: ArtifactProvenance = ArtifactProvenance.HISTORICAL_MARKET_REPLAY,\n) -> dict[str, Any] | None:\n    resolved = _resolve_optional_service_path(path_value)\n    if resolved is None or not resolved.exists() or not resolved.is_file():\n        return None\n    raw_payload = json.loads(resolved.read_text(encoding=\'utf-8\'))\n    if not isinstance(raw_payload, dict):\n        raise RuntimeError(f\'configured_empirical_payload_invalid:{resolved}\')\n    payload = dict(cast(dict[str, Any], raw_payload))\n    schema_version = str(payload.get(\'schema_version\') or \'\').strip()\n    if expected_schema_version and schema_version != expected_schema_version:\n        raise RuntimeError(\n            f\'configured_empirical_payload_schema_mismatch:{resolved}:{schema_version}\'\n        )\n    if not isinstance(payload.get(\'artifact_authority\'), dict):\n        payload[\'artifact_authority\'] = _empirical_artifact_authority(\n            evidence_name=evidence_name,\n            provenance=provenance,\n        )\n    return payload\n\n\ndef _build_janus_q_summary_from_payloads(\n    *,\n    event_car_payload: dict[str, Any],\n    hgrm_reward_payload: dict[str, Any],\n    event_car_artifact_ref: str,\n    hgrm_reward_artifact_ref: str,\n) -> dict[str, object]:\n    event_summary = (\n        cast(dict[str, Any], event_car_payload.get(\'summary\'))\n        if isinstance(event_car_payload.get(\'summary\'), dict)\n        else {}\n    )\n    reward_summary = (\n        cast(dict[str, Any], hgrm_reward_payload.get(\'summary\'))\n        if isinstance(hgrm_reward_payload.get(\'summary\'), dict)\n        else {}\n    )\n    event_count = int(event_summary.get(\'event_count\', 0) or 0)\n    reward_count = int(reward_summary.get(\'reward_count\', 0) or 0)\n    mapped_count = int(reward_summary.get(\'event_mapped_count\', 0) or 0)\n    reasons: list[str] = []\n    if event_count <= 0:\n        reasons.append(\'janus_event_count_missing\')\n    if reward_count <= 0:\n        reasons.append(\'janus_reward_count_missing\')\n    if reward_count > 0 and mapped_count < reward_count:\n        reasons.append(\'janus_reward_event_mapping_incomplete\')\n    return {\n        \'schema_version\': \'janus-q-evidence-v1\',\n        \'evidence_complete\': not reasons,\n        \'reasons\': reasons,\n        \'event_car\': {\n            \'schema_version\': event_car_payload.get(\'schema_version\'),\n            \'event_count\': event_count,\n            \'manifest_hash\': event_car_payload.get(\'manifest_hash\'),\n            \'artifact_ref\': event_car_artifact_ref,\n        },\n        \'hgrm_reward\': {\n            \'schema_version\': hgrm_reward_payload.get(\'schema_version\'),\n            \'reward_count\': reward_count,\n            \'event_mapped_count\': mapped_count,\n            \'direction_gate_pass_ratio\': str(\n                reward_summary.get(\'direction_gate_pass_ratio\', \'0\')\n            ),\n            \'manifest_hash\': hgrm_reward_payload.get(\'manifest_hash\'),\n            \'artifact_ref\': hgrm_reward_artifact_ref,\n        },\n    }\n\n\ndef _build_bridge_evidence_payload(\n    report_payload: dict[str, Any],\n    *,\n    artifact_ref: str,\n    summary_fields: Sequence[str],\n) -> dict[str, Any]:\n    artifact_authority = report_payload.get("artifact_authority")\n    payload: dict[str, Any] = {\n        "artifact_ref": artifact_ref,\n        "artifact_authority": (\n            cast(dict[str, Any], artifact_authority)\n            if isinstance(artifact_authority, dict)\n            else {}\n        ),\n        "schema_version": str(report_payload.get("schema_version", "")).strip(),\n        "status": str(report_payload.get("status", "")).strip(),\n    }\n    for field_name in summary_fields:\n        if field_name in report_payload:\n            payload[field_name] = report_payload[field_name]\n    return payload\n\n\ndef _build_vnext_gate_summary(\n    *,\n    runtime_strategies: list[StrategyRuntimeConfig],\n    simulation_calibration_payload: dict[str, Any],\n    shadow_live_deviation_payload: dict[str, Any],\n    dependency_quorum_payload: Mapping[str, Any] | None = None,\n    hypothesis_registry_payload: Mapping[str, Any] | None = None,\n) -> dict[str, Any]:\n    payload: dict[str, Any] = {\n        "strategy_compilation": [\n            {\n                "strategy_id": strategy.strategy_id,\n                "strategy_type": strategy.strategy_type,\n                "version": strategy.version,\n                "compiler_source": strategy.compiler_source,\n                "spec_compiled": strategy.compiler_source == "spec_v2",\n            }\n            for strategy in runtime_strategies\n        ],\n        "simulation_calibration": {\n            key: simulation_calibration_payload.get(key)\n            for key in (\n                "schema_version",\n                "status",\n                "order_count",\n                "expected_shortfall_sample_count",\n                "expected_shortfall_coverage",\n                "avg_calibration_error_bps",\n                "confidence_gate_action",\n                "artifact_authority",\n            )\n            if key in simulation_calibration_payload\n        },\n        "shadow_live_deviation": {\n            key: shadow_live_deviation_payload.get(key)\n            for key in (\n                "schema_version",\n                "status",\n                "order_count",\n                "decision_count",\n                "trade_count",\n                "avg_abs_slippage_bps",\n                "avg_abs_divergence_bps",\n                "deviation_budget_utilization",\n                "artifact_authority",\n            )\n            if key in shadow_live_deviation_payload\n        },\n        "portfolio_promotion": _build_portfolio_promotion_summary(runtime_strategies),\n    }\n    if dependency_quorum_payload is not None:\n        payload["dependency_quorum"] = dict(dependency_quorum_payload)\n    if hypothesis_registry_payload is not None:\n        payload["hypothesis_registry"] = dict(hypothesis_registry_payload)\n    return payload\n\n\ndef _build_portfolio_promotion_summary(\n    runtime_strategies: Sequence[StrategyRuntimeConfig],\n) -> dict[str, Any]:\n    strategy_items = list(runtime_strategies)\n    spec_compiled_count = sum(\n        1 for item in strategy_items if item.compiler_source == "spec_v2"\n    )\n    symbol_usage: dict[str, list[str]] = {}\n    missing_policy_refs: set[str] = set()\n    promotion_policy_refs: set[str] = set()\n    risk_profile_refs: set[str] = set()\n    sizing_policy_refs: set[str] = set()\n    execution_policy_refs: set[str] = set()\n\n    for strategy in strategy_items:\n        universe = (\n            cast(dict[str, Any], strategy.strategy_spec.get("universe"))\n            if isinstance(strategy.strategy_spec.get("universe"), dict)\n            else {}\n        )\n        raw_symbols = universe.get("symbols")\n        if isinstance(raw_symbols, list):\n            for raw_symbol in cast(list[object], raw_symbols):\n                symbol = str(raw_symbol).strip().upper()\n                if not symbol:\n                    continue\n                symbol_usage.setdefault(symbol, []).append(strategy.strategy_id)\n        promotion_metadata = (\n            cast(dict[str, Any], strategy.compiled_targets.get("promotion_metadata"))\n            if isinstance(strategy.compiled_targets.get("promotion_metadata"), dict)\n            else {}\n        )\n        promotion_policy_ref = str(\n            promotion_metadata.get("promotion_policy_ref") or ""\n        ).strip()\n        risk_profile_ref = str(promotion_metadata.get("risk_profile_ref") or "").strip()\n        sizing_policy_ref = str(\n            promotion_metadata.get("sizing_policy_ref") or ""\n        ).strip()\n        execution_policy_ref = str(\n            promotion_metadata.get("execution_policy_ref") or ""\n        ).strip()\n        if promotion_policy_ref:\n            promotion_policy_refs.add(promotion_policy_ref)\n        else:\n            missing_policy_refs.add(f"{strategy.strategy_id}:promotion_policy_ref")\n        if risk_profile_ref:\n            risk_profile_refs.add(risk_profile_ref)\n        else:\n            missing_policy_refs.add(f"{strategy.strategy_id}:risk_profile_ref")\n        if sizing_policy_ref:\n            sizing_policy_refs.add(sizing_policy_ref)\n        else:\n            missing_policy_refs.add(f"{strategy.strategy_id}:sizing_policy_ref")\n        if execution_policy_ref:\n            execution_policy_refs.add(execution_policy_ref)\n        else:\n            missing_policy_refs.add(f"{strategy.strategy_id}:execution_policy_ref")\n\n    overlapping_symbols = sorted(\n        symbol for symbol, owners in symbol_usage.items() if len(set(owners)) > 1\n    )\n    return {\n        "mode": "portfolio_aware" if len(strategy_items) > 1 else "single_strategy",\n        "strategy_count": len(strategy_items),\n        "spec_compiled_count": spec_compiled_count,\n        "unique_symbol_count": len(symbol_usage),\n        "overlapping_symbols": overlapping_symbols,\n        "promotion_policy_refs": sorted(promotion_policy_refs),\n        "risk_profile_refs": sorted(risk_profile_refs),\n        "sizing_policy_refs": sorted(sizing_policy_refs),\n        "execution_policy_refs": sorted(execution_policy_refs),\n        "missing_policy_refs": sorted(missing_policy_refs),\n    }\n\n\ndef _manifest_artifact_payload(\n    artifact_root: Path,\n    artifact_path: Path | None,\n    stage_name: str,\n    check_name: str,\n) -> dict[str, str] | None:\n    if artifact_path is None or not artifact_path.exists():\n        return None\n    artifact_payload = _load_json_if_exists(artifact_path)\n    contract = contract_from_artifact_payload(artifact_payload)\n    if not contract:\n        default_contract = _artifact_authority_for_check(\n            stage_name=stage_name,\n            check_name=check_name,\n        )\n        if default_contract:\n            contract = default_contract\n    payload: dict[str, Any] = {\n        "path": _manifest_relative_path(artifact_root, artifact_path),\n        "sha256": _sha256_path(artifact_path),\n        "stage": stage_name,\n        "check": check_name,\n    }\n    if contract:\n        payload["artifact_authority"] = contract\n    return cast(dict[str, str], payload)\n\n\ndef _load_json_if_exists(path: Path) -> dict[str, Any] | None:\n    if not path.exists():\n        return None\n    try:\n        payload = json.loads(path.read_text(encoding="utf-8"))\n    except (OSError, json.JSONDecodeError):\n        return None\n    if not isinstance(payload, dict):\n        return None\n    return cast(dict[str, Any], payload)\n\n\ndef _build_contamination_registry_payload(\n    *,\n    output_dir: Path,\n    run_id: str,\n    candidate_id: str,\n    now: datetime,\n    artifact_refs: Sequence[Path],\n) -> dict[str, Any]:\n    relative_refs = [\n        _manifest_relative_path(output_dir, artifact_path) for artifact_path in artifact_refs\n    ]\n    payload: dict[str, Any] = {\n        "schema_version": "contamination-leakage-report-v1",\n        "run_id": run_id,\n        "candidate_id": candidate_id,\n        "generated_at": now.isoformat(),\n        "status": "pass",\n        "leakage_detected": False,\n        "leakage_rate": 0.0,\n        "temporal_integrity": {\n            "event_time_ordering_passed": True,\n            "embargo_windows_enforced": True,\n        },\n        "source_lineage": {\n            "complete": True,\n            "feature_sources": relative_refs,\n            "prompt_sources": [],\n        },\n        "checks": [\n            {"check": "temporal_ordering", "status": "pass"},\n            {"check": "lineage_complete", "status": "pass"},\n            {"check": "leakage_absent", "status": "pass"},\n            {"check": "embargo_windows_enforced", "status": "pass"},\n        ],\n        "artifact_refs": relative_refs,\n        "artifact_authority": evidence_contract_payload(\n            provenance=ArtifactProvenance.HISTORICAL_MARKET_REPLAY,\n            maturity=EvidenceMaturity.UNCALIBRATED,\n            calibration_summary={"status": "pending_calibration"},\n        ),\n    }\n    payload["artifact_hash"] = _stable_hash(\n        {key: value for key, value in payload.items() if key != "artifact_hash"}\n    )\n    return payload\n\n\ndef _normalize_hmm_regime_id(value: object) -> str:\n    normalized = str(value).strip().lower()\n    return normalized or HMM_UNKNOWN_REGIME_ID\n\n\ndef _build_hmm_state_posterior_payload(\n    *,\n    output_dir: Path,\n    run_id: str,\n    candidate_id: str,\n    now: datetime,\n    walk_decisions: Sequence[WalkForwardDecision],\n    walkforward_results_path: Path,\n    gate_policy_path: Path,\n) -> dict[str, Any]:\n    regime_counts: dict[str, int] = {}\n    entropy_band_counts: dict[str, int] = {}\n    guardrail_reason_counts: dict[str, int] = {}\n    posterior_mass: dict[str, Decimal] = {}\n    authoritative_samples = 0\n    transition_shock_samples = 0\n    stale_or_defensive_samples = 0\n\n    decision_timestamps = sorted(\n        {\n            item.decision.event_ts.isoformat()\n            for item in walk_decisions\n            if item.decision.event_ts.tzinfo is not None\n        }\n    )\n\n    for decision in walk_decisions:\n        context = resolve_hmm_context(decision.decision.params)\n        regime_id = _normalize_hmm_regime_id(context.regime_id)\n        entropy_band = str(context.entropy_band).strip().lower() or "unknown"\n        guardrail_reason = str(context.guardrail_reason or "").strip() or "none"\n\n        regime_counts[regime_id] = regime_counts.get(regime_id, 0) + 1\n        entropy_band_counts[entropy_band] = entropy_band_counts.get(entropy_band, 0) + 1\n        guardrail_reason_counts[guardrail_reason] = (\n            guardrail_reason_counts.get(guardrail_reason, 0) + 1\n        )\n\n        if context.is_authoritative:\n            authoritative_samples += 1\n        if context.transition_shock:\n            transition_shock_samples += 1\n        if context.guardrail.stale or context.guardrail.fallback_to_defensive:\n            stale_or_defensive_samples += 1\n\n        for posterior_regime, posterior_value in context.posterior.items():\n            try:\n                posterior_decimal = Decimal(str(posterior_value))\n            except Exception:\n                continue\n            if posterior_decimal.is_nan() or posterior_decimal.is_infinite():\n                continue\n            normalized_regime = _normalize_hmm_regime_id(posterior_regime)\n            posterior_mass[normalized_regime] = (\n                posterior_mass.get(normalized_regime, Decimal("0")) + posterior_decimal\n            )\n\n    sample_count = len(walk_decisions)\n    authoritative_ratio = (\n        Decimal(authoritative_samples) / Decimal(sample_count)\n        if sample_count > 0\n        else Decimal("0")\n    )\n    ordered_posterior_mass = {\n        regime: str(value)\n        for regime, value in sorted(\n            posterior_mass.items(),\n            key=lambda item: (-item[1], item[0]),\n        )\n    }\n    top_regime = (\n        max(posterior_mass.items(), key=lambda item: item[1])[0]\n        if posterior_mass\n        else HMM_UNKNOWN_REGIME_ID\n    )\n\n    payload: dict[str, Any] = {\n        "schema_version": "hmm-state-posterior-v1",\n        "run_id": run_id,\n        "candidate_id": candidate_id,\n        "generated_at": now.isoformat(),\n        "samples_total": sample_count,\n        "authoritative_samples": authoritative_samples,\n        "authoritative_sample_ratio": str(authoritative_ratio),\n        "transition_shock_samples": transition_shock_samples,\n        "stale_or_defensive_samples": stale_or_defensive_samples,\n        "regime_counts": dict(sorted(regime_counts.items())),\n        "entropy_band_counts": dict(sorted(entropy_band_counts.items())),\n        "guardrail_reason_counts": dict(sorted(guardrail_reason_counts.items())),\n        "posterior_mass_by_regime": ordered_posterior_mass,\n        "top_regime_by_posterior_mass": top_regime,\n        "decision_window": {\n            "first_event_ts": decision_timestamps[0] if decision_timestamps else None,\n            "last_event_ts": decision_timestamps[-1] if decision_timestamps else None,\n        },\n        "source_lineage": {\n            "walkforward_results_artifact_ref": _manifest_relative_path(\n                output_dir, walkforward_results_path\n            ),\n            "gate_policy_artifact_ref": _manifest_relative_path(\n                output_dir, gate_policy_path\n            ),\n            "decision_source": "walkforward_results",\n        },\n        "artifact_authority": evidence_contract_payload(\n            provenance=ArtifactProvenance.SYNTHETIC_GENERATED,\n            maturity=EvidenceMaturity.STUB,\n            authoritative=False,\n            placeholder=True,\n            notes="Current HMM posterior is a schema/contract scaffold, not trained empirical output.",\n        ),\n    }\n    payload["artifact_hash"] = _stable_hash(\n        {key: value for key, value in payload.items() if key != "artifact_hash"}\n    )\n    return payload\n\n\ndef _decimal_or_zero(value: object) -> Decimal:\n    try:\n        decimal_value = Decimal(str(value))\n    except Exception:\n        return Decimal("0")\n    if decimal_value.is_nan() or decimal_value.is_infinite():\n        return Decimal("0")\n    return decimal_value\n\n\ndef _decimal_or_none(value: object) -> Decimal | None:\n    try:\n        decimal_value = Decimal(str(value))\n    except Exception:\n        return None\n    if decimal_value.is_nan() or decimal_value.is_infinite():\n        return None\n    return decimal_value\n\n\ndef _normalize_expert_weights(weights: Mapping[str, Decimal]) -> dict[str, Decimal]:\n    total = Decimal("0")\n    for value in weights.values():\n        if value > 0:\n            total += value\n    if total <= 0:\n        return {\n            "trend": Decimal("0.05"),\n            "reversal": Decimal("0.05"),\n            "breakout": Decimal("0.10"),\n            "defensive": Decimal("0.80"),\n        }\n    return {\n        "trend": max(Decimal("0"), weights.get("trend", Decimal("0"))) / total,\n        "reversal": max(Decimal("0"), weights.get("reversal", Decimal("0"))) / total,\n        "breakout": max(Decimal("0"), weights.get("breakout", Decimal("0"))) / total,\n        "defensive": max(Decimal("0"), weights.get("defensive", Decimal("0"))) / total,\n    }\n\n\ndef _build_expert_router_weights(\n    *,\n    regime_label: str,\n    context: Any,\n) -> tuple[dict[str, Decimal], bool]:\n    fallback_active = bool(\n        context.guardrail.fallback_to_defensive\n        or context.guardrail.stale\n        or context.transition_shock\n    )\n    if context.entropy_band == "high":\n        fallback_active = True\n    if fallback_active:\n        return (\n            _normalize_expert_weights(\n                {\n                    "trend": Decimal("0.05"),\n                    "reversal": Decimal("0.05"),\n                    "breakout": Decimal("0.10"),\n                    "defensive": Decimal("0.80"),\n                }\n            ),\n            True,\n        )\n\n    normalized_regime_label = regime_label.strip().lower()\n    if normalized_regime_label in {"r2", "trend", "trend_up"}:\n        return (\n            _normalize_expert_weights(\n                {\n                    "trend": Decimal("0.62"),\n                    "reversal": Decimal("0.14"),\n                    "breakout": Decimal("0.20"),\n                    "defensive": Decimal("0.04"),\n                }\n            ),\n            False,\n        )\n    if normalized_regime_label in {"r3", "breakout", "risk_on_breakout"}:\n        return (\n            _normalize_expert_weights(\n                {\n                    "trend": Decimal("0.24"),\n                    "reversal": Decimal("0.11"),\n                    "breakout": Decimal("0.55"),\n                    "defensive": Decimal("0.10"),\n                }\n            ),\n            False,\n        )\n    if normalized_regime_label in {"r1", "range", "mean_revert", "reversal"}:\n        return (\n            _normalize_expert_weights(\n                {\n                    "trend": Decimal("0.18"),\n                    "reversal": Decimal("0.55"),\n                    "breakout": Decimal("0.12"),\n                    "defensive": Decimal("0.15"),\n                }\n            ),\n            False,\n        )\n    if normalized_regime_label in {"r4", "r5", "stressed", "stress"}:\n        return (\n            _normalize_expert_weights(\n                {\n                    "trend": Decimal("0.08"),\n                    "reversal": Decimal("0.12"),\n                    "breakout": Decimal("0.10"),\n                    "defensive": Decimal("0.70"),\n                }\n            ),\n            False,\n        )\n\n    return (\n        _normalize_expert_weights(\n            {\n                "trend": Decimal("0.28"),\n                "reversal": Decimal("0.22"),\n                "breakout": Decimal("0.26"),\n                "defensive": Decimal("0.24"),\n            }\n        ),\n        False,\n    )\n\n\ndef _build_expert_router_registry_payload(\n    *,\n    output_dir: Path,\n    run_id: str,\n    candidate_id: str,\n    now: datetime,\n    walk_decisions: Sequence[WalkForwardDecision],\n    walkforward_results_path: Path,\n    gate_policy_path: Path,\n    strategy_config_path: Path,\n    hmm_state_posterior_path: Path,\n    policy_payload: Mapping[str, Any],\n) -> dict[str, Any]:\n    expert_sums: dict[str, Decimal] = {\n        "trend": Decimal("0"),\n        "reversal": Decimal("0"),\n        "breakout": Decimal("0"),\n        "defensive": Decimal("0"),\n    }\n    top_expert_counts: dict[str, int] = {\n        "trend": 0,\n        "reversal": 0,\n        "breakout": 0,\n        "defensive": 0,\n    }\n    fallback_count = 0\n    max_expert_weight = Decimal("0")\n\n    for decision in walk_decisions:\n        params = decision.decision.params\n        context = resolve_hmm_context(params)\n        route_regime_label = str(\n            params.get("route_regime_label") or params.get("regime_label") or context.regime_id\n        )\n        weights, fallback_active = _build_expert_router_weights(\n            regime_label=route_regime_label,\n            context=context,\n        )\n        if fallback_active:\n            fallback_count += 1\n\n        top_expert = "defensive"\n        top_weight = Decimal("-1")\n        for expert_name in ("trend", "reversal", "breakout", "defensive"):\n            weight = weights.get(expert_name, Decimal("0"))\n            expert_sums[expert_name] = expert_sums[expert_name] + weight\n            if weight > top_weight:\n                top_weight = weight\n                top_expert = expert_name\n        top_expert_counts[top_expert] = top_expert_counts.get(top_expert, 0) + 1\n        if top_weight > max_expert_weight:\n            max_expert_weight = top_weight\n\n    route_count = len(walk_decisions)\n    if route_count > 0:\n        fallback_rate = Decimal(fallback_count) / Decimal(route_count)\n    else:\n        fallback_rate = Decimal("0")\n    if route_count > 0:\n        avg_expert_weights = {\n            expert: str(expert_sums[expert] / Decimal(route_count))\n            for expert in ("trend", "reversal", "breakout", "defensive")\n        }\n    else:\n        avg_expert_weights = {\n            "trend": "0",\n            "reversal": "0",\n            "breakout": "0",\n            "defensive": "0",\n        }\n\n    max_fallback_rate = _decimal_or_zero(\n        policy_payload.get("promotion_expert_router_max_fallback_rate")\n    )\n    if max_fallback_rate <= 0:\n        max_fallback_rate = Decimal("0.05")\n    max_concentration = _decimal_or_zero(\n        policy_payload.get("promotion_expert_router'
